use std::io::{self, Write};

struct SimulationState {
    total_iterations: usize,
}

impl SimulationState {
    fn new(total_iterations: usize) -> Self {
        SimulationState { total_iterations }
    }

    fn run_simulation(&self) -> io::Result<()> {
        let mut current_step = 0;
        let start_time = std::time::Instant::now();

        print!("Starting Monte Carlo Simulation for Options Pricing...rOkrganizing state and running initial object setup.n");
        io::stdout().flush()?;

        while current_step < self.total_iterations {
            // Simulate doing heavy computation
            std::thread::sleep(std::time::Duration::from_millis(10));

            let progress = (current_step + 1) as f32 / self.total_iterations as f32 * 100.0;

            print!("rProgress: [{}] - {:.2}% complete", "[#]", progress);
            io::stdout().flush()?;
            current_step += 1;
        }

        println!("rSimulation Complete! Final Status Output.n");
        let elapsed = start_time.elapsed().as_secs_f32();
        println!("Total Elapsed Time: {:.2} seconds.", elapsed);
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let state = SimulationState::new(50); 
    state.run_simulation()
}
